mapper.select:
SELECT o.id, o.order_no, o.buyer_id, o.seller_id, o.total_amount, o.status, o.address, o.remark, o.create_time, o.update_time, su.username AS seller_name FROM orders o LEFT JOIN user su ON o.seller_id = su.id WHERE o.buyer_id = #{buyerId}
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT o.id, o.order_no, o.buyer_id, o.seller_id, o.total_amount, o.status, o.address, o.remark, o.create_time, o.update_time, bu.username AS buyer_name FROM orders o LEFT JOIN user bu ON o.buyer_id = bu.id WHERE o.seller_id = #{sellerId}
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT o.id, o.order_no, o.buyer_id, o.seller_id, o.total_amount, o.status, o.address, o.remark, o.create_time, o.update_time, bu.username AS buyer_name, su.username AS seller_name, (SELECT COUNT(*) FROM order_item oi WHERE oi.order_id = o.id) AS item_count FROM orders o LEFT JOIN user bu ON o.buyer_id = bu.id LEFT JOIN user su ON o.seller_id = su.id
o.status = #{status}
ORDER BY o.create_time DESC

SELECT id, order_id, product_id, product_name, product_image, price, quantity
FROM order_item
WHERE order_id = #{orderId}
